import type { Player } from '../types';
import { AIResponseBuilder, type AIResponseData } from '../utils/AIResponseRenderer';

export interface LevelConfig {
    level: number;
    expRequired: number;
    statBonus: {
        strength: number;
        agility: number;
        intelligence: number;
        constitution: number;
        luck: number;
        charisma: number;
    };
    hpBonus: number;
    mpBonus: number;
    skillPoints: number;
    unlocks: string[];
    title?: string;
}

export interface ExpSource {
    type: 'combat' | 'quest' | 'exploration' | 'crafting' | 'social' | 'achievement' | 'daily' | 'event';
    baseExp: number;
    multiplier: number;
    bonus: number;
}

export interface LevelUpReward {
    level: number;
    statPoints: number;
    skillPoints: number;
    gold: number;
    items: Array<{ id: string; name: string; icon: string; quantity: number }>;
    title?: string;
    unlocks: string[];
}

export interface AttributeGrowth {
    strength: number;
    agility: number;
    intelligence: number;
    constitution: number;
    luck: number;
    charisma: number;
}

export class UpgradeSystemV2 {
    private static instance: UpgradeSystemV2;
    private player: Player | null = null;
    private levelConfigs: Map<number, LevelConfig> = new Map();
    private currentExp: number = 0;
    private totalExp: number = 0;
    private attributePoints: number = 0;
    private skillPoints: number = 0;
    private expMultipliers: Map<string, number> = new Map();
    private dailyExpBonus: number = 0;
    private firstWinBonus: boolean = true;

    private constructor() {
        this.initializeLevelConfigs();
        this.initializeExpMultipliers();
    }

    static getInstance(): UpgradeSystemV2 {
        if (!UpgradeSystemV2.instance) {
            UpgradeSystemV2.instance = new UpgradeSystemV2();
        }
        return UpgradeSystemV2.instance;
    }

    private initializeLevelConfigs(): void {
        for (let level = 1; level <= 100; level++) {
            const expRequired = Math.floor(100 * Math.pow(1.15, level - 1));
            const statBonus = {
                strength: Math.floor(level / 5) + 1,
                agility: Math.floor(level / 5) + 1,
                intelligence: Math.floor(level / 5) + 1,
                constitution: Math.floor(level / 5) + 1,
                luck: Math.floor(level / 10) + 1,
                charisma: Math.floor(level / 10) + 1
            };

            this.levelConfigs.set(level, {
                level,
                expRequired,
                statBonus,
                hpBonus: 10 + Math.floor(level / 2),
                mpBonus: 5 + Math.floor(level / 3),
                skillPoints: level % 2 === 0 ? 1 : 0,
                unlocks: this.getLevelUnlocks(level),
                title: this.getLevelTitle(level)
            });
        }
    }

    private getLevelUnlocks(level: number): string[] {
        const unlocks: string[] = [];
        
        if (level === 5) unlocks.push('技能树第二层');
        if (level === 10) unlocks.push('技能树第三层', '副本系统');
        if (level === 15) unlocks.push('公会系统');
        if (level === 20) unlocks.push('竞技场', '称号系统');
        if (level === 30) unlocks.push('神器槽位', '传说装备');
        if (level === 50) unlocks.push('转生系统');
        
        return unlocks;
    }

    private getLevelTitle(level: number): string | undefined {
        if (level >= 100) return '传奇大师';
        if (level >= 90) return '史诗英雄';
        if (level >= 80) return '传奇冒险者';
        if (level >= 70) return '精英战士';
        if (level >= 60) return '资深冒险者';
        if (level >= 50) return '经验丰富的旅者';
        if (level >= 40) return '老练的战士';
        if (level >= 30) return '熟练冒险者';
        if (level >= 20) return '有经验的冒险者';
        if (level >= 10) return '初级冒险者';
        return undefined;
    }

    private initializeExpMultipliers(): void {
        this.expMultipliers.set('combat', 1.0);
        this.expMultipliers.set('quest', 1.2);
        this.expMultipliers.set('exploration', 1.0);
        this.expMultipliers.set('crafting', 0.8);
        this.expMultipliers.set('social', 0.6);
        this.expMultipliers.set('achievement', 1.5);
        this.expMultipliers.set('daily', 1.0);
        this.expMultipliers.set('event', 2.0);
    }

    setPlayer(player: Player): void {
        this.player = player;
        this.currentExp = player.exp ?? 0;
    }

    gainExp(source: ExpSource): AIResponseData {
        if (!this.player) {
            return new AIResponseBuilder('narration')
                .setContent('玩家数据未加载')
                .build();
        }

        const multiplier = this.expMultipliers.get(source.type) ?? 1.0;
        const dailyBonus = source.type === 'daily' ? this.dailyExpBonus : 0;
        const firstWinBonus = source.type === 'combat' && this.firstWinBonus ? 0.5 : 0;

        const totalMultiplier = multiplier + source.multiplier + dailyBonus + firstWinBonus;
        const finalExp = Math.floor(source.baseExp * totalMultiplier + source.bonus);

        this.currentExp += finalExp;
        this.totalExp += finalExp;

        if (source.type === 'combat') {
            this.firstWinBonus = false;
        }

        const levelUpResult = this.checkLevelUp();
        
        if (levelUpResult) {
            return levelUpResult;
        }

        return new AIResponseBuilder('action')
            .setIcon('⭐')
            .action(`获得 ${finalExp} 经验值`)
            .addEffect('exp', finalExp, undefined, '⭐')
            .build();
    }

    private checkLevelUp(): AIResponseData | null {
        if (!this.player) return null;

        const currentLevel = this.player.level ?? 1;
        const config = this.levelConfigs.get(currentLevel);
        
        if (!config) return null;

        if (this.currentExp >= config.expRequired) {
            this.currentExp -= config.expRequired;
            return this.levelUp();
        }

        return null;
    }

    private levelUp(): AIResponseData {
        if (!this.player) return new AIResponseBuilder('narration').setContent('错误').build();

        const oldLevel = this.player.level ?? 1;
        const newLevel = oldLevel + 1;
        const config = this.levelConfigs.get(newLevel);

        if (!config) return new AIResponseBuilder('narration').setContent('已达到最高等级').build();

        this.player.level = newLevel;
        this.attributePoints += 5;
        this.skillPoints += config.skillPoints;

        this.player.maxHp = (this.player.maxHp ?? 100) + config.hpBonus;
        this.player.hp = this.player.maxHp;
        this.player.maxMp = (this.player.maxMp ?? 50) + config.mpBonus;
        this.player.mp = this.player.maxMp;

        const reward: LevelUpReward = {
            level: newLevel,
            statPoints: 5,
            skillPoints: config.skillPoints,
            gold: newLevel * 100,
            items: this.getLevelUpItems(newLevel),
            title: config.title,
            unlocks: config.unlocks
        };

        this.player.gold = (this.player.gold ?? 0) + reward.gold;

        let content = `恭喜升级到 Lv.${newLevel}！\n\n`;
        content += `获得奖励：\n`;
        content += `- 属性点: +${reward.statPoints}\n`;
        content += `- 技能点: +${reward.skillPoints}\n`;
        content += `- 金币: +${reward.gold}\n`;
        content += `- HP上限: +${config.hpBonus}\n`;
        content += `- MP上限: +${config.mpBonus}\n`;
        
        if (reward.title) {
            content += `- 称号: ${reward.title}\n`;
        }
        
        if (reward.unlocks.length > 0) {
            content += `\n解锁内容：\n`;
            reward.unlocks.forEach(unlock => {
                content += `- ${unlock}\n`;
            });
        }

        return new AIResponseBuilder('reward')
            .setIcon('🎉')
            .setTitle('升级！')
            .setContent(content)
            .reward(reward.items, reward.gold, config.expRequired)
            .addEffect('exp', config.expRequired, undefined, '⭐')
            .addEffect('gold', reward.gold, undefined, '💰')
            .addChoice('allocate', '分配属性点', { icon: '📊' })
            .addChoice('skills', '学习技能', { icon: '📚' })
            .build();
    }

    private getLevelUpItems(level: number): Array<{ id: string; name: string; icon: string; quantity: number }> {
        const items: Array<{ id: string; name: string; icon: string; quantity: number }> = [];
        
        if (level % 10 === 0) {
            items.push({ id: 'rare_chest', name: '稀有宝箱', icon: '📦', quantity: 1 });
        }
        
        if (level % 5 === 0) {
            items.push({ id: 'exp_potion', name: '经验药水', icon: '🧪', quantity: 3 });
        }
        
        items.push({ id: 'healing_potion', name: '治疗药水', icon: '❤️', quantity: 5 });
        
        return items;
    }

    allocateAttribute(stat: keyof AttributeGrowth, points: number): AIResponseData {
        if (!this.player) {
            return new AIResponseBuilder('narration')
                .setContent('玩家数据未加载')
                .build();
        }

        if (points > this.attributePoints) {
            return new AIResponseBuilder('narration')
                .setContent('属性点不足')
                .build();
        }

        if (!this.player.stats) {
            this.player.stats = {
                strength: 10,
                agility: 10,
                intelligence: 10,
                constitution: 10,
                luck: 10,
                charisma: 10
            } as import('../types').PlayerStats;
        }

        const statMap: Record<keyof AttributeGrowth, string> = {
            strength: 'strength',
            agility: 'agility',
            intelligence: 'intelligence',
            constitution: 'constitution',
            luck: 'luck',
            charisma: 'charisma'
        };

        const statKey = statMap[stat];
        if (this.player.stats) {
            this.player.stats[statKey] = (this.player.stats[statKey] ?? 0) + points;
        }
        this.attributePoints -= points;

        const statNames: Record<keyof AttributeGrowth, string> = {
            strength: '力量',
            agility: '敏捷',
            intelligence: '智力',
            constitution: '体质',
            luck: '幸运',
            charisma: '魅力'
        };

        return new AIResponseBuilder('action')
            .setIcon('📊')
            .action(`${statNames[stat]} +${points}`)
            .setContent(`剩余属性点: ${this.attributePoints}`)
            .addChoice('continue', '继续分配', { icon: '📊' })
            .addChoice('back', '返回', { icon: '◀️' })
            .build();
    }

    renderUpgradePanel(): AIResponseData {
        if (!this.player) {
            return new AIResponseBuilder('narration')
                .setContent('玩家数据未加载')
                .build();
        }

        const level = this.player.level ?? 1;
        const config = this.levelConfigs.get(level);
        const nextConfig = this.levelConfigs.get(level + 1);

        return new AIResponseBuilder('status')
            .setIcon('⭐')
            .setTitle('升级系统')
            .status({
                name: this.player.name ?? '未知',
                level: level,
                hp: { current: this.player.hp ?? 0, max: this.player.maxHp ?? 100 },
                mp: { current: this.player.mp ?? 0, max: this.player.maxMp ?? 50 },
                gold: this.player.gold ?? 0,
                exp: { current: this.currentExp, max: config?.expRequired ?? 100 }
            })
            .setContent(
                `等级: ${level}\n` +
                `经验: ${this.currentExp}/${config?.expRequired ?? 100}\n` +
                `总经验: ${this.totalExp}\n` +
                `属性点: ${this.attributePoints}\n` +
                `技能点: ${this.skillPoints}\n\n` +
                `下一等级奖励：\n` +
                `- HP +${nextConfig?.hpBonus ?? 0}\n` +
                `- MP +${nextConfig?.mpBonus ?? 0}\n` +
                (nextConfig?.skillPoints ? `- 技能点 +${nextConfig.skillPoints}\n` : '') +
                (nextConfig?.title ? `- 称号: ${nextConfig.title}\n` : '')
            )
            .addChoice('allocate', '分配属性点', { icon: '📊', disabled: this.attributePoints === 0 })
            .addChoice('skills', '技能树', { icon: '🌳' })
            .addChoice('history', '升级历史', { icon: '📜' })
            .build();
    }

    renderAttributeAllocation(): AIResponseData {
        if (!this.player) {
            return new AIResponseBuilder('narration')
                .setContent('玩家数据未加载')
                .build();
        }

        const stats = this.player.stats ?? {
            strength: 10,
            agility: 10,
            intelligence: 10,
            constitution: 10,
            luck: 10,
            charisma: 10
        };

        return new AIResponseBuilder('narration')
            .setIcon('📊')
            .setTitle('属性分配')
            .setContent(
                `可用属性点: ${this.attributePoints}\n\n` +
                `力量: ${stats.strength} - 影响物理攻击\n` +
                `敏捷: ${stats.agility} - 影响速度和闪避\n` +
                `智力: ${stats.intelligence} - 影响魔法攻击\n` +
                `体质: ${stats.constitution} - 影响生命值和防御\n` +
                `幸运: ${stats.luck} - 影响暴击和掉落\n` +
                `魅力: ${stats.charisma} - 影响社交和交易`
            )
            .addChoice('strength', `力量 +1`, { icon: '💪', disabled: this.attributePoints === 0 })
            .addChoice('agility', `敏捷 +1`, { icon: '🏃', disabled: this.attributePoints === 0 })
            .addChoice('intelligence', `智力 +1`, { icon: '🧠', disabled: this.attributePoints === 0 })
            .addChoice('constitution', `体质 +1`, { icon: '❤️', disabled: this.attributePoints === 0 })
            .addChoice('luck', `幸运 +1`, { icon: '🍀', disabled: this.attributePoints === 0 })
            .addChoice('charisma', `魅力 +1`, { icon: '✨', disabled: this.attributePoints === 0 })
            .addChoice('back', '返回', { icon: '◀️' })
            .build();
    }

    setExpMultiplier(type: string, multiplier: number): void {
        this.expMultipliers.set(type, multiplier);
    }

    setDailyExpBonus(bonus: number): void {
        this.dailyExpBonus = bonus;
    }

    resetFirstWinBonus(): void {
        this.firstWinBonus = true;
    }

    getAttributePoints(): number {
        return this.attributePoints;
    }

    getSkillPoints(): number {
        return this.skillPoints;
    }

    useSkillPoints(points: number): boolean {
        if (this.skillPoints >= points) {
            this.skillPoints -= points;
            return true;
        }
        return false;
    }

    getCurrentExp(): number {
        return this.currentExp;
    }

    getTotalExp(): number {
        return this.totalExp;
    }

    getLevelConfig(level: number): LevelConfig | undefined {
        return this.levelConfigs.get(level);
    }
}

export const upgradeSystemV2 = UpgradeSystemV2.getInstance();
export default UpgradeSystemV2;
